# Solution by Kyle

a_l, a_r, a_t = map(int, input().split())
b_l, b_r, b_t = map(int, input().split())

def check_day(a_l, a_r, a_t, b_l, b_r, b_t, day):
    return ((day >= a_l and day <= a_r) or (day >= b_l and day <= b_r)) and ((day + a_t - 1 >= a_l and day + a_t - 1 <= a_r) or (day + a_t - 1 >= b_l and day + a_t - 1 <= b_r)) and ((day + b_t - 1 >= a_l and day + b_t - 1 <= a_r) or (day + b_t - 1 >= b_l and day + b_t - 1 <= b_r))

day = 0
while True:
    if not check_day(a_l, a_r, a_t, b_l, b_r, b_t, day):
        break
    day += 1

print(day)
